"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["85045"],{77662(i){i.exports=JSON.parse('{"tag":{"label":"integration","permalink":"/sysanalyst-kb.github.io/docs/tags/integration","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":18,"items":[{"id":"integration/api-gateway","title":"API Gateway pattern","description":"API Gateway \u2014 \u044D\u0442\u043E \u0435\u0434\u0438\u043D\u0430\u044F \u0442\u043E\u0447\u043A\u0430 \u0432\u0445\u043E\u0434\u0430 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u0432 (web, mobile, third-party), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0437\u0430\u043F\u0440\u043E\u0441\u044B \u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u043A\u0440\u043E\u0441\u0441-\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0438 \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-gateway"},{"id":"integration/enterprise-integration-patterns","title":"Enterprise Integration Patterns (EIP)","description":"Enterprise Integration Patterns (EIP) \u2014 \u044D\u0442\u043E \u043A\u0430\u0442\u0430\u043B\u043E\u0433 \u0442\u0438\u043F\u043E\u0432\u044B\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0434\u043B\u044F \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441\u0438\u0441\u0442\u0435\u043C, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0432 \u043A\u043D\u0438\u0433\u0435 Gregor Hohpe \u0438 Bobby Woolf (2004). EIP \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0430\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u043C \u0438 \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u2014 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0448\u0438\u043D (Kafka, RabbitMQ, Azure Service Bus) \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u044E\u0442 \u044D\u0442\u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B.","permalink":"/sysanalyst-kb.github.io/docs/integration/enterprise-integration-patterns"},{"id":"data/etl-basics","title":"ETL \u2014 \u043E\u0441\u043D\u043E\u0432\u044B","description":"ETL (Extract, Transform, Load) \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0434\u0430\u043D\u043D\u044B\u0445 \u0438\u0437 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432, \u0438\u0445 \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u0438 \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0438 \u0432 \u0446\u0435\u043B\u0435\u0432\u0443\u044E \u0441\u0438\u0441\u0442\u0435\u043C\u0443 (\u043E\u0431\u044B\u0447\u043D\u043E DWH). \u041F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u0440\u0430\u0442\u044C \u0434\u0430\u043D\u043D\u044B\u0435 \u0438\u0437 \u0440\u0430\u0437\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C \u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435 \u0434\u043B\u044F \u0430\u043D\u0430\u043B\u0438\u0437\u0430.","permalink":"/sysanalyst-kb.github.io/docs/data/etl-basics"},{"id":"integration/event-storming","title":"Event Storming","description":"Event Storming \u2014 \u044D\u0442\u043E \u0432\u043E\u0440\u043A\u0448\u043E\u043F-\u0442\u0435\u0445\u043D\u0438\u043A\u0430 \u0434\u043B\u044F \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432 \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u0431\u044B\u0442\u0438\u044F. \u041F\u0440\u0438\u0434\u0443\u043C\u0430\u043B Alberto Brandolini. \u042D\u0442\u043E \u043D\u0435 \u0434\u0438\u0430\u0433\u0440\u0430\u043C\u043C\u0430, \u0430 \u0444\u043E\u0440\u043C\u0430\u0442 \u0432\u0441\u0442\u0440\u0435\u0447\u0438, \u0433\u0434\u0435 \u0432\u0441\u044F \u043A\u043E\u043C\u0430\u043D\u0434\u0430 \u043D\u0430\u043A\u043B\u0435\u0438\u0432\u0430\u0435\u0442 \u0441\u0442\u0438\u043A\u0435\u0440\u044B \u043D\u0430 \u043E\u0433\u0440\u043E\u043C\u043D\u0443\u044E \u0434\u043E\u0441\u043A\u0443.","permalink":"/sysanalyst-kb.github.io/docs/integration/event-storming"},{"id":"integration/event-storming-advanced","title":"Event Storming \u2014 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C","description":"Event Storming \u2014 \u044D\u0442\u043E \u043C\u0435\u0442\u043E\u0434\u0438\u043A\u0430 \u0432\u043E\u0440\u043A\u0448\u043E\u043F\u0430 \u0434\u043B\u044F \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432 \u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u0438\u0441\u0442\u0435\u043C. \u041D\u0430 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u043E\u043C \u0443\u0440\u043E\u0432\u043D\u0435 Event Storming \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E DDD: discovery bounded contexts, \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432, \u0440\u0435\u0432\u0435\u0440\u0441-\u0438\u043D\u0436\u0438\u043D\u0438\u0440\u0438\u043D\u0433 legacy.","permalink":"/sysanalyst-kb.github.io/docs/integration/event-storming-advanced"},{"id":"integration/event-driven-architecture","title":"Event-Driven Architecture (\u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435)","description":"Event-Driven Architecture (EDA) \u2014 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0439 \u0441\u0442\u0438\u043B\u044C, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B \u043E\u0431\u0449\u0430\u044E\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u0430 \u043D\u0435 \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u044F\u043C\u044B\u0435 \u0432\u044B\u0437\u043E\u0432\u044B. \u0415\u0441\u043B\u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u043F\u0440\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u0434\u0435\u043F\u043B\u043E\u044F, \u0442\u043E EDA \u2014 \u043F\u0440\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u0432\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435.","permalink":"/sysanalyst-kb.github.io/docs/integration/event-driven-architecture"},{"id":"integration/kafka","title":"Kafka \u2014 \u0441\u043E\u0431\u044B\u0442\u0438\u0439\u043D\u044B\u0439 streaming","description":"Apache Kafka \u2014 \u044D\u0442\u043E \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0434\u043B\u044F \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0441\u043E\u0431\u044B\u0442\u0438\u0439\u043D\u044B\u0445 \u043F\u043E\u0442\u043E\u043A\u043E\u0432. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 RabbitMQ, Kafka \u043D\u0435 \u0443\u0434\u0430\u043B\u044F\u0435\u0442 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u044F \u2014 \u043E\u043D\u0430 \u0445\u0440\u0430\u043D\u0438\u0442 \u0438\u0445 \u0432 \u043B\u043E\u0433\u0435 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F (retention).","permalink":"/sysanalyst-kb.github.io/docs/integration/kafka"},{"id":"specialization/ai-agents-mcp","title":"MCP \u2014 Model Context Protocol \u0434\u043B\u044F \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u044F \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432","description":"MCP (Model Context Protocol) \u2014 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B \u043E\u0442 Anthropic, \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432 \u0434\u0430\u043D\u043D\u044B\u0445 \u043A AI-\u0430\u0433\u0435\u043D\u0442\u0430\u043C. \u0412\u043C\u0435\u0441\u0442\u043E \u0442\u043E\u0433\u043E \u0447\u0442\u043E\u0431\u044B \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430 \u043F\u0438\u0441\u0430\u0442\u044C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E, MCP \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0435\u0434\u0438\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441: \u0430\u0433\u0435\u043D\u0442 \xab\u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F\xbb \u043A MCP-\u0441\u0435\u0440\u0432\u0435\u0440\u0443 \u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u0434\u043E\u0441\u0442\u0443\u043F \u043A\u043E \u0432\u0441\u0435\u043C \u0435\u0433\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0443 \u0432\u0430\u0436\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C MCP, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E AI-\u0430\u0433\u0435\u043D\u0442\u043E\u0432 \u0441 \u043A\u043E\u0440\u043F\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-agents-mcp"},{"id":"specialization/ecommerce-oms","title":"OMS \u2014 Order Management System","description":"OMS (Order Management System) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0437\u0430\u043A\u0430\u0437\u0430\u043C\u0438, \u044F\u0434\u0440\u043E e-commerce \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B. \u0417\u0430\u043A\u0430\u0437 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 12+ \u0441\u0442\u0430\u0442\u0443\u0441\u043E\u0432 \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u0435\u0442 \u043A\u0430\u0442\u0430\u043B\u043E\u0433 (\u0447\u0442\u043E \u043F\u0440\u043E\u0434\u0430\u043B\u0438), WMS (\u0447\u0442\u043E \u0441\u043E\u0431\u0440\u0430\u043B\u0438), TMS (\u0447\u0442\u043E \u0434\u043E\u0441\u0442\u0430\u0432\u0438\u043B\u0438) \u0438 \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0439 \u0448\u043B\u044E\u0437 (\u0447\u0442\u043E \u043E\u043F\u043B\u0430\u0442\u0438\u043B\u0438). \u0412 \u043F\u0438\u043A\u0435 (Black Friday) OMS \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0442\u044C 10 000+ \u0437\u0430\u043A\u0430\u0437\u043E\u0432/\u0447\u0430\u0441.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-oms"},{"id":"integration/rabbitmq","title":"RabbitMQ \u2014 \u043E\u0447\u0435\u0440\u0435\u0434\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439","description":"RabbitMQ \u2014 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u044B\u0439 \u0431\u0440\u043E\u043A\u0435\u0440 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439. \u0420\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0442 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B AMQP 0-9-1. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F task queues, RPC, \u0438 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439 \u043F\u043E \u0441\u043B\u043E\u0436\u043D\u044B\u043C \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C.","permalink":"/sysanalyst-kb.github.io/docs/integration/rabbitmq"},{"id":"specialization/gamedev-sdk","title":"SDK-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0432 \u0438\u0433\u0440\u0430\u0445 \u2014 Firebase, GameAnalytics, Push","description":"\u041C\u043E\u0431\u0438\u043B\u044C\u043D\u0430\u044F \u0438\u0433\u0440\u0430 \u2014 \u043D\u0435 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u041E\u043D\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442 5\u201310+ SDK (Analytics, Push, Crash, Monetization, Attribution). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442, \u043A\u0430\u043A\u0438\u0435 SDK \u043D\u0443\u0436\u043D\u044B, \u043A\u0430\u043A\u0438\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F \u043E\u043D\u0438 \u0448\u043B\u044E\u0442, \u043A\u0430\u043A \u0434\u0430\u043D\u043D\u044B\u0435 \u0442\u0435\u043A\u0443\u0442 \u043E\u0442 \u043A\u043B\u0438\u0435\u043D\u0442\u0430 \u0432 DWH \u0438 \u043A\u0430\u043A\u0438\u0435 \u0440\u0438\u0441\u043A\u0438 \u0443 \u043A\u0430\u0436\u0434\u043E\u0439 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0413\u043B\u0430\u0432\u043D\u043E\u0435: SDK \u2014 \u044D\u0442\u043E \u043A\u043E\u0434 \u0432 \u043A\u043B\u0438\u0435\u043D\u0442\u0435, \u0435\u0433\u043E \u043D\u0430\u0434\u043E \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C, \u043E\u0431\u043D\u043E\u0432\u043B\u044F\u0442\u044C \u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u0442\u044C. \u041E\u0448\u0438\u0431\u043A\u0430 \u0432 SDK \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u043E\u0438\u0442\u044C revenue (\u043F\u043E\u0442\u0435\u0440\u044F\u043D\u043D\u044B\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F) \u0438\u043B\u0438 \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0430 (\u043A\u0440\u0430\u0448).","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-sdk"},{"id":"integration/api-soap-wsdl","title":"SOAP / WSDL \u0434\u043B\u044F \u0440\u0430\u0431\u043E\u0442\u044B \u0441 legacy-\u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438","description":"\u0412 2025 \u0433\u043E\u0434\u0443 \u043D\u043E\u0432\u044B\u0439 \u043F\u0440\u043E\u0435\u043A\u0442 \u0432\u0440\u044F\u0434 \u043B\u0438 \u043D\u0430\u0447\u043D\u0443\u0442 \u043D\u0430 SOAP. \u041D\u043E \u0431\u0430\u043D\u043A\u0438, \u0441\u0442\u0440\u0430\u0445\u043E\u0432\u044B\u0435, \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0438 \u043A\u0440\u0443\u043F\u043D\u044B\u0435 \u0440\u0438\u0442\u0435\u0439\u043B\u0435\u0440\u044B \u0432\u0441\u0451 \u0435\u0449\u0451 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 SOAP-\u0441\u0435\u0440\u0432\u0438\u0441\u044B, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0435 10\u201315 \u043B\u0435\u0442 \u043D\u0430\u0437\u0430\u0434. \u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u0443\u043C\u0435\u0442\u044C \u0447\u0438\u0442\u0430\u0442\u044C WSDL \u0438 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C, \u043A\u0430\u043A \u0443\u0441\u0442\u0440\u043E\u0435\u043D \u043E\u0431\u043C\u0435\u043D \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u0432 SOAP.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-soap-wsdl"},{"id":"integration/async-message-queue","title":"\u0410\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 (Message Queue)","description":"\u0414\u043E \u0441\u0438\u0445 \u043F\u043E\u0440 \u043C\u044B \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u0438 \u043E \u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u043C REST: \u043A\u043B\u0438\u0435\u043D\u0442 \u0434\u0435\u043B\u0430\u0435\u0442 \u0437\u0430\u043F\u0440\u043E\u0441 \u0438 \u0436\u0434\u0451\u0442 \u043E\u0442\u0432\u0435\u0442. \u041D\u043E \u0435\u0441\u0442\u044C \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0438, \u0433\u0434\u0435 \u0436\u0434\u0430\u0442\u044C \u043D\u0435\u043B\u044C\u0437\u044F \u0438\u043B\u0438 \u043D\u0435 \u043D\u0443\u0436\u043D\u043E. \u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0430\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043E\u0447\u0435\u0440\u0435\u0434\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439.","permalink":"/sysanalyst-kb.github.io/docs/integration/async-message-queue"},{"id":"specialization/logistics-integrations","title":"\u0418\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441 \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441\u0430\u043C\u0438 \u0438 \u043A\u0443\u0440\u044C\u0435\u0440\u0430\u043C\u0438","description":"\u041B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0441 \u0434\u0435\u0441\u044F\u0442\u043A\u0430\u043C\u0438 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432 \u0430\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0441\u0442\u044C (Webhook + Polling), \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u043E\u0448\u0438\u0431\u043E\u043A, \u0440\u0435\u0442\u0440\u0430\u0438, \u0438\u0434\u0435\u043C\u043F\u043E\u0442\u0435\u043D\u0442\u043D\u043E\u0441\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-integrations"},{"id":"specialization/medtech-lis","title":"\u041B\u0418\u0421 \u2014 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u044B\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u041B\u0418\u0421 (\u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u0430\u044F \u0418\u0421) \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u043C \u0430\u043D\u0430\u043B\u0438\u0437\u0430 \u0431\u0438\u043E\u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u0448\u0442\u0440\u0438\u0445\u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u0438\u0440\u043E\u043A, \u0430\u0432\u0442\u043E\u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F (70%+ \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432 \u0431\u0435\u0437 \u0443\u0447\u0430\u0441\u0442\u0438\u044F \u043B\u0430\u0431\u043E\u0440\u0430\u043D\u0442\u0430), \u0440\u0435\u0444\u0435\u0440\u0435\u043D\u0441\u043D\u044B\u0435 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B\u044B \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F \u0441 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u044B\u043C\u0438 \u0430\u043D\u0430\u043B\u0438\u0437\u0430\u0442\u043E\u0440\u0430\u043C\u0438. \u0412 \u0442\u0438\u043F\u043E\u0432\u043E\u0439 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u0438 \u2014 10 000+ \u043F\u0440\u043E\u0431/\u0434\u0435\u043D\u044C, \u0434\u043E 500 \u0432\u0438\u0434\u043E\u0432 \u0430\u043D\u0430\u043B\u0438\u0437\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-lis"},{"id":"specialization/medtech-mis","title":"\u041C\u0418\u0421 \u2014 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u041C\u0418\u0421 (\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430) \u2014 \u043E\u0441\u043D\u043E\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0431\u043E\u043B\u044C\u043D\u0438\u0446\u044B \u0438\u043B\u0438 \u043F\u043E\u043B\u0438\u043A\u043B\u0438\u043D\u0438\u043A\u0438. \u041E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u042D\u041C\u041A, \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u0435, \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u044E, \u0440\u0430\u0434\u0438\u043E\u043B\u043E\u0433\u0438\u044E, \u0430\u043F\u0442\u0435\u043A\u0443, \u043E\u0442\u0447\u0451\u0442\u043D\u043E\u0441\u0442\u044C \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u0415\u0413\u0418\u0421\u0417. \u041A\u043B\u044E\u0447\u0435\u0432\u043E\u0439 \u0432\u044B\u0437\u043E\u0432: \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0439 (10+ \u043F\u043E\u0434\u0441\u0438\u0441\u0442\u0435\u043C) \u0438 compliance (323-\u0424\u0417, 152-\u0424\u0417). \u041A\u0440\u0443\u043F\u043D\u0435\u0439\u0448\u0430\u044F \u041C\u0418\u0421 \u0420\u0424 \u2014 \u0415\u041C\u0418\u0410\u0421 \u041C\u043E\u0441\u043A\u0432\u044B \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 100M+ \u0437\u0430\u043F\u0438\u0441\u0435\u0439/\u0433\u043E\u0434.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-mis"},{"id":"specialization/govtech-smev","title":"\u0421\u041C\u042D\u0412 \u2014 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435","description":"\u0421\u041C\u042D\u0412 \u2014 \xab\u0448\u0438\u043D\u0430\xbb \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438. \u0412\u0435\u0440\u0441\u0438\u044F 3 (\u0442\u0435\u043A\u0443\u0449\u0430\u044F) \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 REST \u0438 JSON (\u0440\u0430\u043D\u0435\u0435 SOAP/XML). \u0427\u0435\u0440\u0435\u0437 \u0421\u041C\u042D\u0412 \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 1B+ \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432/\u0433\u043E\u0434, 25 000+ \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0451\u043D\u043D\u044B\u0445 \u0413\u0418\u0421. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 5-30 \u0441\u0435\u043A), \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0437\u043D\u0430\u0447\u0438\u043C\u043E\u0441\u0442\u044C (\u0423\u041A\u042D\u041F). \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u044B: \u0415\u0421\u0418\u0410 (\u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F + \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435), \u0448\u043B\u044E\u0437 \u0421\u041C\u042D\u0412 (ViPNet, \u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-smev"},{"id":"basics/what-is-api","title":"\u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 API","description":"API \u2014 \u044D\u0442\u043E \u043C\u0435\u043D\u044E \u0440\u0435\u0441\u0442\u043E\u0440\u0430\u043D\u0430. \u041E\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442, \u0447\u0442\u043E \u043A\u0443\u0445\u043D\u044F \u0443\u043C\u0435\u0435\u0442 \u0433\u043E\u0442\u043E\u0432\u0438\u0442\u044C, \u043A\u0430\u043A\u0438\u0435 \u0431\u043B\u044E\u0434\u0430 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B \u0438 \u043A\u0430\u043A \u0438\u0445 \u0437\u0430\u043A\u0430\u0437\u044B\u0432\u0430\u0442\u044C. \u0411\u0435\u0437 \u043C\u0435\u043D\u044E \u0432\u044B \u043D\u0435 \u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0437\u0430\u043A\u0430\u0437\u0430\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/basics/what-is-api"}],"unlisted":false}}')}}]);